);
CREATE TABLE testimonials (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  customer_name   TEXT NOT NULL,
  occasion        TEXT,
  city            TEXT,
  year            INTEGER,
  quote           TEXT NOT NULL,
  photo_r2_key    TEXT,
  is_visible      INTEGER DEFAULT 1,
  display_order   INTEGER DEFAULT 0
);
INSERT INTO "testimonials" ("id","customer_name","occasion","city","year","quote","photo_r2_key","is_visible","display_order") VALUES(1,'Priya Sharma','Wedding','Delhi',2024,'The detail in my bridal mehndi was breathtaking. Every guest asked who the artist was. She understood exactly what I wanted before I could even explain it.',NULL,1,1);
INSERT INTO "testimonials" ("id","customer_name","occasion","city","year","quote","photo_r2_key","is_visible","display_order") VALUES(2,'Ananya Gupta','Engagement','Jaipur',2024,'I was nervous about my engagement mehndi but she made the whole experience so calming. The design was elegant and the colour came out so dark — exactly what I hoped for.',NULL,1,2);
INSERT INTO "testimonials" ("id","customer_name","occasion","city","year","quote","photo_r2_key","is_visible","display_order") VALUES(3,'Meera Patel','Wedding','Lucknow',2023,'She travelled to Lucknow for my wedding and was worth every penny. My mehndi lasted over three weeks and I still look at the photos. Truly an artist.',NULL,1,3);
INSERT INTO "testimonials" ("id","customer_name","occasion","city","year","quote","photo_r2_key","is_visible","display_order") VALUES(4,'sanket','bridal','pune',2026,'loved it :love',NULL,1,0);
