CREATE TABLE IF NOT EXISTS "bookings" (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  booking_ref TEXT UNIQUE NOT NULL,
  
  
  service_id INTEGER NULL,
  
  
  appointment_date TEXT NOT NULL,
  appointment_time TEXT,
  
  
  customer_name TEXT NOT NULL,
  customer_phone TEXT NOT NULL,
  customer_whatsapp TEXT,
  customer_email TEXT,
  customer_city TEXT,
  customer_pincode TEXT,
  customer_address TEXT,
  
  
  event_type TEXT,
  event_date TEXT,
  notes TEXT,
  
  
  occasion_type TEXT,
  is_bridal INTEGER DEFAULT 0,
  bridal_scope TEXT,
  family_headcount INTEGER DEFAULT 0,
  family_design_style TEXT,
  headcount_range TEXT,
  headcount_numeric INTEGER,
  design_style TEXT,
  body_coverage TEXT,
  addons TEXT,
  booking_urgency TEXT,
  location_type TEXT,
  venue_address TEXT,
  travel_charge INTEGER DEFAULT 0,
  estimated_duration_mins INTEGER,
  recommended_package TEXT,
  estimated_price_min INTEGER,
  estimated_price_max INTEGER,
  is_multiday INTEGER DEFAULT 0,
  reference_image_urls TEXT,
  admin_notes TEXT,
  final_confirmed_price INTEGER,
  
  status TEXT DEFAULT 'pending',
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
, status_updated_at TEXT, decline_reason TEXT, assigned_artist_id INTEGER REFERENCES artists(id));
